function u(t){if(!t)return"";const r=new Date(t),a=r.getFullYear(),n=String(r.getMonth()+1).padStart(2,"0"),o=String(r.getDate()).padStart(2,"0");return`${a}-${n}-${o}`}function e(t){if(!t||t<=0)return"0分钟";const r=Math.floor(t/3600),a=Math.floor(t%3600/60);let n="";return r>0&&(n+=`${r}小时`),a>0&&(n+=`${a}分钟`),n||"0分钟"}function f(t,r=50){return t?t.length<=r?t:t.substring(0,r)+"...":""}export{e as a,u as f,f as t};
